async def add_football_on_patch():
    objs = await get_all_objects()
    patch = next((o for o in objs['objects'] if 'patch' in o['name']), None)
    if patch:
        return await add_object('football', patch['position'][0], patch['position'][1], patch['position'][2] + 0.05, shape='sphere', color='white', size=0.04)
    return {'success': False, 'message': 'Patch not found'}
